const binary = $input.first().binary;

const sheetNames = [
  'demand_global',
  'demand_transaction',
  'demand_asset',
  'demand_region',
  'demand_departement',
  'ranking_global_war',
  'audience'
];

return sheetNames.map(name => ({
  json: { sheetName: name },
  binary: binary
}));

// Group all rows by sheetName, keep last 24 rows (2 years monthly)
const sheets = {};

for (const item of $input.all()) {
  const name = item.json.sheetName ?? 'Unknown';
  if (!sheets[name]) sheets[name] = [];
  const { sheetName: _ignored, ...rowData } = item.json;
  sheets[name].push(rowData);
}

return Object.entries(sheets).map(([name, rows]) => ({
  json: {
    sheetName: name,
    rows: rows.slice(-24)
  }
}));

const item = $input.first();
const { sheetName, rows } = item.json;

// Helper: get distinct sorted values
const distinct = (arr) => [...new Set(arr)].sort();

// Helper: friendly label truncation
const short = (s, n=15) => s && s.length > n ? s.slice(0,n)+'…' : s;

let chartConfig = null;

// --- demand_global: line chart volume over time ---
if (sheetName === 'demand_global') {
  const labels = rows.map(r => r.date || r.mois || r.month || Object.values(r)[0]);
  const volumes = rows.map(r => {
    const v = r.volume || r.clicks || r.impressions || Object.values(r)[1];
    return isNaN(Number(v)) ? 0 : Number(v);
  });
  chartConfig = {
    type: 'line',
    data: {
      labels,
      datasets: [{
        label: 'Search Volume',
        data: volumes,
        fill: true,
        backgroundColor: 'rgba(66,133,244,0.15)',
        borderColor: '#4285F4',
        borderWidth: 2,
        pointRadius: 3,
        tension: 0.3
      }]
    },
    options: {
      plugins: { title: { display: true, text: 'Demand Global — Monthly Volume', font: { size: 16 } } },
      scales: { y: { beginAtZero: false } }
    }
  };
}

// --- demand_transaction: grouped bar by segment ---
else if (sheetName === 'demand_transaction') {
  const dateKey = Object.keys(rows[0]).find(k => k.toLowerCase().includes('date') || k.toLowerCase().includes('mois')) || Object.keys(rows[0])[0];
  const segKey  = Object.keys(rows[0]).find(k => k.toLowerCase().includes('segment') || k.toLowerCase().includes('transaction')) || Object.keys(rows[0])[1];
  const volKey  = Object.keys(rows[0]).find(k => k.toLowerCase().includes('volume') || k.toLowerCase().includes('click')) || Object.keys(rows[0])[2];

  const dates    = distinct(rows.map(r => r[dateKey])).slice(-12);
  const segments = distinct(rows.map(r => r[segKey]));

  const palette = ['#4285F4','#EA4335','#FBBC05','#34A853','#9C27B0','#FF6D00','#00ACC1'];

  const datasets = segments.map((seg, i) => {
    const data = dates.map(d => {
      const match = rows.find(r => r[dateKey] === d && r[segKey] === seg);
      return match ? Number(match[volKey]) || 0 : 0;
    });
    return { label: seg, data, backgroundColor: palette[i % palette.length] };
  });

  chartConfig = {
    type: 'bar',
    data: { labels: dates, datasets },
    options: {
      plugins: { title: { display: true, text: 'Demand by Transaction Segment', font: { size: 16 } } },
      scales: { x: { stacked: false }, y: { stacked: false, beginAtZero: true } }
    }
  };
}

// --- demand_asset: stacked bar by asset type ---
else if (sheetName === 'demand_asset') {
  const dateKey  = Object.keys(rows[0]).find(k => k.toLowerCase().includes('date') || k.toLowerCase().includes('mois')) || Object.keys(rows[0])[0];
  const assetKey = Object.keys(rows[0]).find(k => k.toLowerCase().includes('asset') || k.toLowerCase().includes('type') || k.toLowerCase().includes('bien')) || Object.keys(rows[0])[1];
  const volKey   = Object.keys(rows[0]).find(k => k.toLowerCase().includes('volume') || k.toLowerCase().includes('click')) || Object.keys(rows[0])[2];

  const dates  = distinct(rows.map(r => r[dateKey])).slice(-12);
  const assets = distinct(rows.map(r => r[assetKey]));
  const palette = ['#4285F4','#EA4335','#FBBC05','#34A853','#9C27B0'];

  const datasets = assets.map((asset, i) => {
    const data = dates.map(d => {
      const match = rows.find(r => r[dateKey] === d && r[assetKey] === asset);
      return match ? Number(match[volKey]) || 0 : 0;
    });
    return { label: short(String(asset)), data, backgroundColor: palette[i % palette.length] };
  });

  chartConfig = {
    type: 'bar',
    data: { labels: dates, datasets },
    options: {
      plugins: { title: { display: true, text: 'Demand by Asset Type', font: { size: 16 } } },
      scales: { x: { stacked: true }, y: { stacked: true, beginAtZero: true } }
    }
  };
}

// --- demand_region: horizontal bar top 15 regions ---
else if (sheetName === 'demand_region') {
  const regionKey = Object.keys(rows[0]).find(k => k.toLowerCase().includes('region') || k.toLowerCase().includes('région')) || Object.keys(rows[0])[0];
  const volKey    = Object.keys(rows[0]).find(k => k.toLowerCase().includes('volume') || k.toLowerCase().includes('click')) || Object.keys(rows[0])[1];

  // Aggregate volume per region across all rows
  const totals = {};
  for (const r of rows) {
    const region = r[regionKey];
    totals[region] = (totals[region] || 0) + (Number(r[volKey]) || 0);
  }
  const sorted = Object.entries(totals).sort((a, b) => b[1] - a[1]).slice(0, 15);

  chartConfig = {
    type: 'bar',
    data: {
      labels: sorted.map(([k]) => k),
      datasets: [{ label: 'Total Volume', data: sorted.map(([, v]) => v), backgroundColor: '#4285F4' }]
    },
    options: {
      indexAxis: 'y',
      plugins: { title: { display: true, text: 'Top 15 Regions by Search Volume', font: { size: 16 } } },
      scales: { x: { beginAtZero: true } }
    }
  };
}

// --- demand_departement: horizontal bar top 15 départements ---
else if (sheetName === 'demand_departement') {
  const deptKey = Object.keys(rows[0]).find(k => k.toLowerCase().includes('dept') || k.toLowerCase().includes('departement') || k.toLowerCase().includes('département')) || Object.keys(rows[0])[0];
  const volKey  = Object.keys(rows[0]).find(k => k.toLowerCase().includes('volume') || k.toLowerCase().includes('click')) || Object.keys(rows[0])[1];

  const totals = {};
  for (const r of rows) {
    const dept = r[deptKey];
    totals[dept] = (totals[dept] || 0) + (Number(r[volKey]) || 0);
  }
  const sorted = Object.entries(totals).sort((a, b) => b[1] - a[1]).slice(0, 15);

  chartConfig = {
    type: 'bar',
    data: {
      labels: sorted.map(([k]) => k),
      datasets: [{ label: 'Total Volume', data: sorted.map(([, v]) => v), backgroundColor: '#34A853' }]
    },
    options: {
      indexAxis: 'y',
      plugins: { title: { display: true, text: 'Top 15 Départements by Search Volume', font: { size: 16 } } },
      scales: { x: { beginAtZero: true } }
    }
  };
}

// --- ranking_global_war: multi-line rank over time (lower = better) ---
else if (sheetName === 'ranking_global_war') {
  const dateKey = Object.keys(rows[0]).find(k => k.toLowerCase().includes('date') || k.toLowerCase().includes('mois')) || Object.keys(rows[0])[0];
  const hostKey = Object.keys(rows[0]).find(k => k.toLowerCase().includes('host') || k.toLowerCase().includes('url') || k.toLowerCase().includes('domain')) || Object.keys(rows[0])[1];
  const rankKey = Object.keys(rows[0]).find(k => k.toLowerCase().includes('rank') || k.toLowerCase().includes('rang') || k.toLowerCase().includes('position')) || Object.keys(rows[0])[2];

  const dates = distinct(rows.map(r => r[dateKey])).slice(-12);
  const hosts = distinct(rows.map(r => r[hostKey]));
  const palette = ['#4285F4','#EA4335','#FBBC05','#34A853','#9C27B0','#FF6D00'];

  const datasets = hosts.map((host, i) => {
    const data = dates.map(d => {
      const match = rows.find(r => r[dateKey] === d && r[hostKey] === host);
      return match ? Number(match[rankKey]) || null : null;
    });
    return {
      label: short(String(host), 20),
      data,
      borderColor: palette[i % palette.length],
      backgroundColor: 'transparent',
      borderWidth: 2,
      pointRadius: 3,
      tension: 0.3,
      spanGaps: true
    };
  });

  chartConfig = {
    type: 'line',
    data: { labels: dates, datasets },
    options: {
      plugins: { title: { display: true, text: 'SEO Ranking — Competitors (lower = better)', font: { size: 16 } } },
      scales: { y: { reverse: true, beginAtZero: false } }
    }
  };
}

// --- audience: doughnut brand vs nonbrand vs anonymous ---
else if (sheetName === 'audience') {
  // Sum volumes per audience type across all rows
  const brandKey     = Object.keys(rows[0]).find(k => k.toLowerCase().includes('brand') && !k.toLowerCase().includes('non') && !k.toLowerCase().includes('anon'));
  const nonbrandKey  = Object.keys(rows[0]).find(k => k.toLowerCase().includes('nonbrand') || (k.toLowerCase().includes('non') && k.toLowerCase().includes('brand')));
  const anonymousKey = Object.keys(rows[0]).find(k => k.toLowerCase().includes('anon'));

  if (brandKey && nonbrandKey) {
    const brand     = rows.reduce((s, r) => s + (Number(r[brandKey])     || 0), 0);
    const nonbrand  = rows.reduce((s, r) => s + (Number(r[nonbrandKey])  || 0), 0);
    const anonymous = anonymousKey ? rows.reduce((s, r) => s + (Number(r[anonymousKey]) || 0), 0) : 0;

    const labels = anonymousKey ? ['Brand', 'Non-brand', 'Anonymous'] : ['Brand', 'Non-brand'];
    const data   = anonymousKey ? [brand, nonbrand, anonymous] : [brand, nonbrand];

    chartConfig = {
      type: 'doughnut',
      data: {
        labels,
        datasets: [{
          data,
          backgroundColor: ['#4285F4', '#34A853', '#FBBC05'],
          borderWidth: 2
        }]
      },
      options: {
        plugins: {
          title: { display: true, text: 'Audience Split — Brand vs Non-brand', font: { size: 16 } },
          legend: { position: 'bottom' }
        }
      }
    };
  } else {
    // Fallback: bar chart with all numeric columns
    const numericKeys = Object.keys(rows[0]).filter(k => !isNaN(Number(rows[0][k])));
    const labelKey = Object.keys(rows[0])[0];
    chartConfig = {
      type: 'bar',
      data: {
        labels: rows.map(r => r[labelKey]),
        datasets: numericKeys.map((k, i) => ({
          label: k,
          data: rows.map(r => Number(r[k]) || 0),
          backgroundColor: ['#4285F4','#34A853','#FBBC05'][i] || '#9E9E9E'
        }))
      },
      options: {
        plugins: { title: { display: true, text: 'Audience Data', font: { size: 16 } } }
      }
    };
  }
}

// Generic fallback: bar chart first numeric column over first text column
if (!chartConfig) {
  const keys = Object.keys(rows[0]);
  const labelKey  = keys[0];
  const valueKey  = keys.find((k, i) => i > 0 && !isNaN(Number(rows[0][k]))) || keys[1];
  chartConfig = {
    type: 'bar',
    data: {
      labels: rows.map(r => String(r[labelKey]).slice(0, 15)),
      datasets: [{
        label: valueKey,
        data: rows.map(r => Number(r[valueKey]) || 0),
        backgroundColor: '#4285F4'
      }]
    },
    options: {
      plugins: { title: { display: true, text: sheetName, font: { size: 16 } } }
    }
  };
}

return [{ json: { sheetName, chartConfig } }];

// Pass through sheetName alongside the binary image
const item = $input.first();
return [{
  json: { sheetName: $('Build Chart Config').first().json.sheetName },
  binary: item.binary
}];
